import 'package:flutter/material.dart';

void main() => runApp(const MyApp());

class MyApp extends StatelessWidget {
  const MyApp({super.key});

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Responsive Demo',
      home: Scaffold(
        appBar: AppBar(title: const Text('Responsive Layout')),
        body: SafeArea(
          child: Padding(
            padding: const EdgeInsets.all(16),
            child: LayoutBuilder(
              builder: (context, constraints) {
                if (constraints.maxWidth > 600) {
                  // Wide layout
                  return Row(
                    children: [
                      Expanded(
                        child: Container(
                          color: Colors.blue.shade100,
                          padding: const EdgeInsets.all(16),
                          child: const Center(child: Text('Left Panel')),
                        ),
                      ),
                      const SizedBox(width: 16),
                      Expanded(
                        child: Container(
                          color: Colors.green.shade100,
                          padding: const EdgeInsets.all(16),
                          child: const Center(child: Text('Right Panel')),
                        ),
                      ),
                    ],
                  );
                } else {
                  // Narrow layout
                  return Column(
                    children: [
                      Expanded(
                        child: Container(
                          color: Colors.blue.shade100,
                          padding: const EdgeInsets.all(16),
                          child: const Center(child: Text('Top Panel')),
                        ),
                      ),
                      const SizedBox(height: 16),
                      Expanded(
                        child: Container(
                          color: Colors.green.shade100,
                          padding: const EdgeInsets.all(16),
                          child: const Center(child: Text('Bottom Panel')),
                        ),
                      ),
                    ],
                  );
                }
              },
            ),
          ),
        ),
      ),
    );
  }
}
